        "import yfinance as yf\n",
        "df_nq = yf.download('NQ=F', interval= '30m', period= '60d')\n",
        "df_nq.columns = ['_'.join(col).strip() if isinstance(col, tuple) else col for col in df_nq.columns]\n",
        "df_nq.columns = [c.split('_')[0].lower() for c in df_nq.columns]\n",
        "df_nq = df_nq[['open', 'high', 'low', 'close', 'volume']]\n",
        "system5 = VPORBSystem(instrument= 'NQ', equity=2000)\n",
        "stats5 = system5.run_backtest(df_nq)\n",
        "for k, v in stats5.items():\n",
        "  print(f\"{k:<25} {v}\")"
